using Azure.Core;
using Azure.Generator.Management.Models;
using Azure.Generator.Management.Snippets;
using Azure.Generator.Management.Utilities;
using Azure.ResourceManager;
using Microsoft.TypeSpec.Generator.Primitives;
using Microsoft.TypeSpec.Generator.Providers;
using Microsoft.TypeSpec.Generator.Statements;
using System.Collections.Generic;
using System.Linq;
using static Microsoft.TypeSpec.Generator.Snippets.Snippet;

namespace Azure.Generator.Management.Providers
{
    internal sealed class MockableArmClientProvider : MockableResourceProvider
    {
        private MockableArmClientProvider(IReadOnlyList<ResourceClientProvider> resources, IReadOnlyList<NonResourceMethod> nonResourceMethods)
            : base(typeof(ArmClient), OperationContext.Create(RequestPathPattern.Tenant), resources, new Dictionary<ResourceClientProvider, IReadOnlyList<ResourceMethod>>(), nonResourceMethods)
        {
        }

        /// <summary>
        /// Creates a new instance of <see cref="MockableArmClientProvider"/> if there are resources or non-resource methods to generate methods for.
        /// </summary>
        /// <param name="resources">The resources to generate methods for.</param>
        /// <param name="nonResourceMethods">The non-resource methods to generate methods for.</param>
        /// <returns>A new instance of <see cref="MockableArmClientProvider"/> if there are resources or non-resource methods, otherwise null.</returns>
        public static MockableArmClientProvider? TryCreate(IReadOnlyList<ResourceClientProvider> resources, IReadOnlyList<NonResourceMethod> nonResourceMethods)
        {
            if (resources.Count == 0 && nonResourceMethods.Count == 0)
            {
                return null;
            }
            return new MockableArmClientProvider(resources, nonResourceMethods);
        }

        protected override MethodProvider[] BuildMethods()
        {
            var methods = new List<MethodProvider>(_resources.Count + _nonResourceMethods.Count * 2);

            // Build methods for extension resources
            foreach (var resource in _resources)
            {
                methods.Add(BuildGetResourceIdMethodForResource(resource));
                if (resource.IsExtensionResource)
                {
                    if (resource.IsSingleton)
                    {
                        methods.AddRange(BuildMethodsForExtensionSingletonResource(resource));
                    }
                    else
                    {
                        methods.AddRange(BuildMethodsForExtensionNonSingletonResource(resource));
                    }
                }
            }

            // Build methods for non-resource extension operations
            foreach (var method in _nonResourceMethods)
            {
                // Process both async and sync method variants
                methods.Add(BuildServiceMethod(method.InputMethod, method.InputClient, true));
                methods.Add(BuildServiceMethod(method.InputMethod, method.InputClient, false));
            }

            return [.. methods];
        }

        private MethodProvider BuildGetResourceIdMethodForResource(ResourceClientProvider resource)
        {
            var idParameter = new ParameterProvider("id", $"The resource ID of the resource to get.", typeof(ResourceIdentifier));
            var signature = new MethodSignature(
                $"Get{resource.Name}",
                $"Gets an object representing a {resource.Type:C} along with the instance operations that can be performed on it but with no data.",
                //"\nYou can use <see cref=\"{resource.Name}.CreateResourceIdentifier\" /> to create a {resource.Type:C} {typeof(ResourceIdentifier):C} from its components.",
                // TODO -- we cannot include this method reference in cref because we do not have that method generated yet.
                MethodSignatureModifiers.Public | MethodSignatureModifiers.Virtual,
                resource.Type,
                $"Returns a {resource.Type:C} object.",
                [idParameter]);

            var body = new MethodBodyStatement[]
            {
                Static(resource.Type).Invoke("ValidateResourceId", idParameter).Terminate(),
                Return(New.Instance(resource.Type,
                    [
                        This.As<ArmResource>().Client(),
                        idParameter
                    ]))
            };

            return new MethodProvider(signature, body, this);
        }

        private IList<MethodProvider> BuildMethodsForExtensionNonSingletonResource(ResourceClientProvider resource)
        {
            var result = new List<MethodProvider>();
            var scopeParameter = new ParameterProvider("scope", $"The scope of the resource collection to get.", typeof(ResourceIdentifier));
            var extraParameters = resource.FactoryMethodSignature.Parameters;
            var signature = new MethodSignature(
                $"{resource.FactoryMethodSignature.Name}",
                $"Gets a collection of {resource.ResourceCollection!.Type:C} objects within the specified scope.",
                MethodSignatureModifiers.Public | MethodSignatureModifiers.Virtual,
                resource.ResourceCollection!.Type,
                $"Returns a collection of {resource.Type:C} objects.",
                [scopeParameter, .. extraParameters]);
            var body = new MethodBodyStatement[]
            {
                Return(New.Instance(resource.ResourceCollection!.Type,
                    [
                        This.As<ArmResource>().Client(),
                        scopeParameter,
                        .. extraParameters
                    ]))
            };
            result.Add(new MethodProvider(signature, body, this));

            var collection = resource.ResourceCollection!;
            var getMethod = collection.Methods.FirstOrDefault(m => m.Signature.Name == "Get");
            var getAsyncMethod = collection.Methods.FirstOrDefault(m => m.Signature.Name == "GetAsync");
            if (getMethod is not null)
            {
                result.Add(BuildGetMethod(this, getMethod, signature, $"Get{resource.ResourceName}"));
            }
            if (getAsyncMethod is not null)
            {
                result.Add(BuildGetMethod(this, getAsyncMethod, signature, $"Get{resource.ResourceName}Async"));
            }

            return result;

            static MethodProvider BuildGetMethod(TypeProvider enclosingType, MethodProvider resourceGetMethod, MethodSignature collectionGetSignature, string methodName)
            {
                var parameters = new List<ParameterProvider>(resourceGetMethod.Signature.Parameters);
                var insertIndex = 0;
                foreach (var p in collectionGetSignature.Parameters)
                {
                    if (!parameters.Any(existing => existing.Name == p.Name))
                    {
                        parameters.Insert(insertIndex, p);
                        insertIndex++;
                    }
                }

                var signature = new MethodSignature(
                    methodName,
                    resourceGetMethod.Signature.Description,
                    resourceGetMethod.Signature.Modifiers,
                    resourceGetMethod.Signature.ReturnType,
                    resourceGetMethod.Signature.ReturnDescription,
                    parameters,
                    Attributes: [new AttributeStatement(typeof(ForwardsClientCallsAttribute))]);

                return new MethodProvider(
                    signature,
                    Return(This.Invoke(collectionGetSignature).Invoke(resourceGetMethod.Signature)),
                    enclosingType);
            }
        }

        private IList<MethodProvider> BuildMethodsForExtensionSingletonResource(ResourceClientProvider resource)
        {
            var result = new List<MethodProvider>();

            var scopeParameter = new ParameterProvider("scope", $"The scope that the resource will apply against.", typeof(ResourceIdentifier));
            var extraParameters = resource.FactoryMethodSignature.Parameters;
            var signature = new MethodSignature(
                $"{resource.FactoryMethodSignature.Name}",
                $"Gets an object representing a {resource.Type:C} along with the instance operations that can be performed on it in the ArmClient",
                MethodSignatureModifiers.Public | MethodSignatureModifiers.Virtual,
                resource.Type,
                $"Returns a {resource.Type:C} object.",
                [scopeParameter, .. extraParameters]);

            var body = new MethodBodyStatement[]
            {
                Return(New.Instance(resource.Type,
                    [
                        This.As<ArmResource>().Client(),
                        MockableResourceProvider.BuildSingletonResourceIdentifier(scopeParameter.As<ResourceIdentifier>(), resource.ResourceTypeValue, resource.SingletonResourceName!)
                    ]))
            };

            var getByScopeMethod = new MethodProvider(signature, body, this);
            result.Add(getByScopeMethod);

            return result;
        }
    }
}

# resolveArmResources API Integration

## Overview

This document describes the integration of the `resolveArmResources` API from `@azure-tools/typespec-azure-resource-manager` into our codebase.

## Background

The `resolveArmResources` API is a standardized way provided by the TypeSpec ARM library to extract and resolve ARM resource information from TypeSpec definitions. It provides:

- Fully resolved resource operations (CRUD + actions + lists)
- Resource hierarchy and parent-child relationships
- Resource scope detection (Tenant, Subscription, ResourceGroup, etc.)
- Proper handling of extension resources
- Categorization of non-resource operations

## Purpose

We want to migrate from our custom resource detection logic in `resource-detection.ts` to use the standardized `resolveArmResources` API. This will:

1. Reduce maintenance burden by leveraging the standard library
2. Ensure consistency with other TypeSpec-based generators
3. Benefit from improvements and bug fixes in the ARM library
4. Simplify our codebase

## Implementation Approach

The migration is being done incrementally:

### Step 1: Create Conversion Function (✅ Complete)

- Created `resolve-arm-resources-converter.ts` that wraps `resolveArmResources` and converts `Provider` format to our `ArmProviderSchema` format
- Integrated comprehensive test validation in `resource-detection.test.ts` and `non-resource-methods.test.ts`
- All 27 tests pass, validating the converter produces identical results to the existing implementation
- The converter maintains full compatibility with existing code while using the standardized API internally

### Step 2: Add Feature Flag (✅ Complete)

- Added a configuration option `use-legacy-resource-detection` as a feature flag to control resource detection behavior
- By default, the flag is **on** (true), maintaining current legacy behavior for backward compatibility
- When disabled (false), `buildArmProviderSchema` calls the converter to use `resolveArmResources` instead of custom logic
- This allows controlled testing and gradual rollout to specific services or scenarios
- Each service can opt-in to the new API by disabling the flag in their TypeSpec configuration file (`tspconfig.yaml`)

**How to opt-in to the new resolveArmResources API:**

Add the following to your `tspconfig.yaml` or emitter options:

```yaml
emit:
  - "@azure-typespec/http-client-csharp-mgmt"
options:
  "@azure-typespec/http-client-csharp-mgmt":
    use-legacy-resource-detection: false
```

### Step 3: Enable Flag in Test Projects (Next)

- Enable the `use-legacy-resource-detection: false` flag in our internal test projects
- Validate that all test projects generate correctly with the new resolveArmResources API
- Identify and fix any issues found during test project generation
- Ensure comprehensive coverage of different TypeSpec patterns and scenarios

### Step 4: Validate with Real Resource Providers (Next)

- Enable the `use-legacy-resource-detection: false` flag in a selected set of real RPs
- Start with a few representative RPs that cover common patterns
- Monitor generation and validate SDK output quality
- Gather feedback and address any issues discovered
- Gradually expand to more RPs as confidence increases

### Step 5: Enable by Default and Remove Flag (Final)

- After sufficient validation with test projects and real RPs, flip the default to `false` (making resolveArmResources the default)
- Remove the feature flag and always use `resolveArmResources`
- The conversion function will remain to translate from `Provider` format to our `ArmProviderSchema` format
- Eventually consider updating downstream code to work directly with `Provider` format if beneficial

## Data Structure Mapping

### Provider (from resolveArmResources)
```typescript
interface Provider {
  resources?: ResolvedResource[];
  providerOperations?: ArmResourceOperation[];
}

interface ResolvedResource {
  type: Model;
  kind: "Tracked" | "Proxy" | "Extension" | "Other";
  providerNamespace: string;
  operations: ArmResolvedOperationsForResource;
  associatedOperations?: ArmResourceOperation[];
  resourceName: string;
  resourceType: ResourceType;
  resourceInstancePath: string;
  parent?: ResolvedResource;
  scope?: string | ResolvedResource;
}
```

### ArmProviderSchema (our format)
```typescript
interface ArmProviderSchema {
  resources: ArmResourceSchema[];
  nonResourceMethods: NonResourceMethod[];
}

interface ArmResourceSchema {
  resourceModelId: string;
  metadata: ResourceMetadata;
}

interface ResourceMetadata {
  resourceIdPattern: string;
  resourceType: string;
  methods: ResourceMethod[];
  resourceScope: ResourceScope;
  parentResourceId?: string;
  parentResourceModelId?: string;
  singletonResourceName?: string;
  resourceName: string;
}
```

## Next Steps

1. **Enable in test projects** - Enable the `use-legacy-resource-detection: false` flag in internal test projects to validate generation
2. **Validate with real RPs** - Enable the flag in a few representative real RPs to ensure stability and gather feedback
3. **Monitor and iterate** - Collect feedback and address any edge cases discovered during rollout
4. **Make default** - After successful validation, flip the default to `false` (making resolveArmResources the default behavior)
5. **Remove flag** - Remove the feature flag configuration, always use `resolveArmResources`
6. **Long-term** - Consider updating downstream code to work directly with `Provider` format if beneficial
